import{_ as s,c as a,o as n,a4 as e}from"./chunks/framework.HaEZziQ1.js";const l="/FrontEndLearnNotes/assets/v2-00f404b15b562d5060e2f1d5bfc6fcb8_720w.rqsQQ6ys.webp",o="/FrontEndLearnNotes/assets/v2-8dde17f4b6b54dedee82d69635d8de49_720w.BKchL6BX.webp",p="/FrontEndLearnNotes/assets/v2-24585e1fc912e194125faf38d036c185_720w.Vdswmi99.webp",t="/FrontEndLearnNotes/assets/v2-06255189e813e0280590eb6037be32b2_720w.DYA1SXfY.webp",r="/FrontEndLearnNotes/assets/v2-43b0b442e5ef3c820122899599fc0f04_720w.Dqe1yWlb.webp",c="/FrontEndLearnNotes/assets/v2-f583d2e64283ebd9b8b62a84414d009d_720w.Bzjd6xog.webp",i="/FrontEndLearnNotes/assets/v2-8ccdc774e7f0343bdf3f6421365d8e70_720w.BzAkmYyh.webp",u="/FrontEndLearnNotes/assets/v2-99681165f9ac57f46319652275193373_720w.fYlEnnXj.webp",B="/FrontEndLearnNotes/assets/v2-19c224b36e44d469426199c052d8e29a_720w.BrYPNDJg.webp",d="/FrontEndLearnNotes/assets/v2-7ce7c4ea7a3a193a84511b2f58dd4940_720w.XmfNy6Jo.webp",y="/FrontEndLearnNotes/assets/v2-ae4f2f90c27edec06ed067c37eac07ee_720w.CfqaZKwE.webp",h="/FrontEndLearnNotes/assets/v2-217e4f747bde46c2189fc61ac28bf4bf_720w.Be107Bgh.webp",b="/FrontEndLearnNotes/assets/v2-7b56a5d57022f776fa77823be0022d44_720w.veUWHRgL.webp",m="/FrontEndLearnNotes/assets/v2-23ac9465c39e6587a723c915361db970_720w.Fq3jwgVM.webp",v="/FrontEndLearnNotes/assets/v2-a2f1ad589f2ee638ee730a60968c63c8_720w.eGziCE5g.webp",g="/FrontEndLearnNotes/assets/v2-6b4a53cb59f02853c84ad390a4c09ee5_720w.B6fvGMbY.webp",A="/FrontEndLearnNotes/assets/v2-206f31ccc054c32400b26ada402b804c_720w.SdbGAkAC.webp",F="/FrontEndLearnNotes/assets/v2-9a6fbf1cfc218b4512bf294b62aca8d0_720w.Bbq8KPb8.webp",f="/FrontEndLearnNotes/assets/v2-1d5377d341e0e0f182d08eed0a50e978_720w.C3BVJRwu.webp",J=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端面试相关/JavaScript面试题/待定.md","filePath":"Document/前端面试相关/JavaScript面试题/待定.md","lastUpdated":null}'),E={name:"Document/前端面试相关/JavaScript面试题/待定.md"},C=e(`<h2 id="待定" tabindex="-1">待定 <a class="header-anchor" href="#待定" aria-label="Permalink to &quot;待定&quot;">​</a></h2><h3 id="说一下-js-原生事件如何绑定" tabindex="-1">说一下 JS 原生事件如何绑定 <a class="header-anchor" href="#说一下-js-原生事件如何绑定" aria-label="Permalink to &quot;说一下 JS 原生事件如何绑定&quot;">​</a></h3><p>答：JS 原生绑定事件主要为三种：</p><ul><li>一是 html 事件处理程序</li><li>二是 DOM0 级事件处理程序</li><li>三是 DOM2 级事件处理程序</li></ul><p>其中：html 事件现在早已不用了，就是在 html 各种标签上直接添加事件，类似于 css 的行内样式，缺点是不好维护，因为散落在标签中,也就是耦合度太高</p><p>例如：<code>&lt;button onclick=&quot;事件处理函数&quot;&gt;点我&lt;/button&gt;</code></p><p>第二类是 DOM0 级事件，目前在 PC 端用的还是比较多的绑定事件方式，兼容性也好，主要是先获取 dom 元素，然后直接给 dom 元素添加事件</p><p>例如：</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> btn</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> document</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">getElementById</span><span style="color:#ABB2BF;">(‘</span><span style="color:#E06C75;">id元素</span><span style="color:#ABB2BF;">’)</span></span>
<span class="line"><span style="color:#E5C07B;">btn</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">onclick</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> function</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"> // 要处理的事件逻辑</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>DOM0 事件如何移除呢？很简单：<code>btn.onclick=null;</code>置为空就行</p><p>优点：兼容性好</p><p>缺点：只支持冒泡，不支持捕获</p><p>第三类是 DOM2 级事件，移动端用的比较多，也有很多优点，提供了专门的绑定和移除方法</p><p>例如：</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> btn</span><span style="color:#56B6C2;">=</span><span style="color:#E5C07B;">document</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">getElementById</span><span style="color:#ABB2BF;">(‘</span><span style="color:#E06C75;">id元素</span><span style="color:#ABB2BF;">’)</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 绑定事件</span></span>
<span class="line"><span style="color:#E5C07B;">btn</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">addEventListener</span><span style="color:#ABB2BF;">(‘</span><span style="color:#E06C75;">click</span><span style="color:#ABB2BF;">’,</span><span style="color:#E06C75;">绑定的事件处理函数名</span><span style="color:#ABB2BF;">,</span><span style="color:#D19A66;">false</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 移除事件</span></span>
<span class="line"><span style="color:#E5C07B;">btn</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">removeEventListener</span><span style="color:#ABB2BF;">(‘</span><span style="color:#E06C75;">click</span><span style="color:#ABB2BF;">’,</span><span style="color:#E06C75;">要移除的事件处理函数名</span><span style="color:#ABB2BF;">，</span><span style="color:#D19A66;">false</span><span style="color:#ABB2BF;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>优点：支持给个元素绑定多个相同事件，支持冒泡和捕获事件机制</p><h3 id="说一下-js-原生常用-dom-操作方法" tabindex="-1">说一下 JS 原生常用 dom 操作方法？ <a class="header-anchor" href="#说一下-js-原生常用-dom-操作方法" aria-label="Permalink to &quot;说一下 JS 原生常用 dom 操作方法？&quot;">​</a></h3><p>答：js 原生 dom 操作方法有？</p><p>查找：getElementByid,</p><p>getElementsByTagName,</p><p>querySelector,</p><p>querySelectorAll</p><p>插入：appendChild,insertBefore</p><p>删除：removeChild</p><p>克隆：cloneNode</p><p>设置和获取属性：setAttribute(“属性名”,”值”),getAttibute(“属性名”)</p><h3 id="说一下-es6-新增特性" tabindex="-1">说一下 ES6 新增特性? <a class="header-anchor" href="#说一下-es6-新增特性" aria-label="Permalink to &quot;说一下 ES6 新增特性?&quot;">​</a></h3><p>答：ES6 新增特性常用的主要有：let/const,箭头函数，模板字符串，解构赋值，模块的导入(import)和导出(export default/export),Promise,还有一些数组字符串的新方法,其实有很多，我平时常用的就这些**(了解)JS 设计模式有哪些(单例模式<a href="https://www.zhihu.com/search?q=%E8%A7%82%E5%AF%9F%E8%80%85%E6%A8%A1%E5%BC%8F&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22answer%22%2C%22sourceId%22%3A2603050043%7D" target="_blank" rel="noreferrer">观察者模式</a>等)**</p><p>答：JS 设计模式有很多，但我知道的有单例模式，观察者模式</p><p>单例模式：就是保证一个类只有一个实例，实现的方法一般是先判断实例存在与否，如果存在直接返回，如果不存在就创建了再返回，这就确保了一个类只有一个实例对象。在 JavaScript 里，单例作为一个命名空间提供者，从全局命名空间里提供一个唯一的访问点来访问该对象。</p><p>观察者模式: 观察者的使用场合就是：当一个对象的改变需要同时改变其它对象，并且它不知道具体有多少对象需要改变的时候，就应该考虑使用观察者模式。</p><p>总的来说，观察者模式所做的工作就是在解耦，让耦合的双方都依赖于抽象，而不是依赖于具体。从而使得各自的变化都不会影响到另一边的变化</p><h3 id="说一下你对-js-面试对象的理解" tabindex="-1">说一下你对 JS 面试对象的理解 <a class="header-anchor" href="#说一下你对-js-面试对象的理解" aria-label="Permalink to &quot;说一下你对 JS 面试对象的理解&quot;">​</a></h3><p>答：JS 面向对象主要基于 function 来实现的，通过 function 来模拟类，通过 prototype 来实现类方法的共享，跟其他语言有着本质的不同，自从有了 ES6 后，把面向对象类的实现更像后端语言的实现了，通过 class 来定义类，通过 extends 来继承父类，其实 ES6 类的实现本质上是一个语法糖，不过对于开发简单了好多。</p><h3 id="说一下-js-数组常用方法-至少-6-个" tabindex="-1">说一下 JS 数组常用方法（至少 6 个） <a class="header-anchor" href="#说一下-js-数组常用方法-至少-6-个" aria-label="Permalink to &quot;说一下 JS 数组常用方法（至少 6 个）&quot;">​</a></h3><p>答：在开发中，数组使用频率很频繁，JS 数组常用方法</p><p>有:push,pop,unshift,shift,splice,join,concat,forEach,filter,map,sort,some,every 好多，不过都是平时开发中很常用的方法,大家可以补充一点儿 es6 的</p><h3 id="说一下-js-数组内置遍历方法有哪些和区别" tabindex="-1">说一下 JS 数组内置遍历方法有哪些和区别 <a class="header-anchor" href="#说一下-js-数组内置遍历方法有哪些和区别" aria-label="Permalink to &quot;说一下 JS 数组内置遍历方法有哪些和区别&quot;">​</a></h3><p>答：JS 数组内置遍历（遍历就是循环的意思）方法主要有： **forEach:**这个方法是为了取代 for 循环遍历数组的，返回值为 undefined 例如： let arrInfo=[4,6,6,8,5,7,87] arrInfo.forEach((item,index,arr)=&gt;{ //遍历逻辑 }) 其中： item 代码遍历的每一项, index:代表遍历的每项的索引， arr 代表数组本身 **filter:**是一个过滤遍历的方法，如果返回条件为 true，则返回满足条件为 true 的新数组 let arrInfo=[4,16,6,8,45,7,87] let resultArr=arrInfo.filter((item,index,arr)=&gt;{ //例如返回数组每项值大于 9 的数组 return item&gt;9 }) **map:**这个 map 方法主要对数组的复杂逻辑处理时用的多，特别是 react 中遍历数据，也经常用到，写法和 forEach 类似 **some:**这个 some 方法用于只要数组中至少存在一个满足条件的结果，返回值就为 true,否则返回 fasel, 写法和 forEach 类似 **every:**这个 every 方法用于数组中每一项都得满足条件时，才返回 true，否则返回 false, 写法和 forEach 类似</p><h3 id="说一下-js-作用域和作用域链" tabindex="-1">说一下 JS 作用域和作用域链 <a class="header-anchor" href="#说一下-js-作用域和作用域链" aria-label="Permalink to &quot;说一下 JS 作用域和作用域链&quot;">​</a></h3><p>答：JS 作用域也就是 JS 识别变量的范围，作用域链也就是 JS 查找变量的顺序 先说作用域，JS 作用域主要包括全局作用域、局部作用域和 ES6 的块级作用域 全局作用域：也就是定义在 window 下的变量范围，在任何地方都可以访问， 局部作用域：是只在函数内部定义的变量范围 块级作用域：简单来说用 let 和 const 在任意的代码块中定义的变量都认为是块级作用域中的变量，例如在 for 循环中用 let 定义的变量，在 if 语句中用 let 定义的变量等等 注：尽量不要使用全局变量，因为容易导致全局的污染，命名冲突，对 bug 查找不利。 2️ 而所谓的作用域链就是由最内部的作用域往最外部,查找变量的过程.形成的链条就是作用域链</p><h3 id="说一下从输入-url-到页面加载完中间发生了什么" tabindex="-1">说一下从输入 URL 到页面加载完中间发生了什么？ <a class="header-anchor" href="#说一下从输入-url-到页面加载完中间发生了什么" aria-label="Permalink to &quot;说一下从输入 URL 到页面加载完中间发生了什么？&quot;">​</a></h3><p>答：大致过程是这样的：DNS 解析 TCP 连接发送 HTTP 请求服务器处理请求并返回需要的数据浏览器解析渲染页面连接结束输入了一个域名,域名要通过 DNS 解析找到这个域名对应的服务器地址(ip),通过 TCP 请求链接服务,通过 WEB 服务器(apache)返回数据,浏览器根据返回数据构建 DOM 树,通过 css 渲染引擎及 js 解析引擎将页面渲染出来,关闭 tcp 连接</p><h3 id="说一下-js-事件代理-也称事件委托-是什么-及实现原理" tabindex="-1">说一下 JS 事件代理（也称事件委托）是什么，及实现原理？ <a class="header-anchor" href="#说一下-js-事件代理-也称事件委托-是什么-及实现原理" aria-label="Permalink to &quot;说一下 JS 事件代理（也称事件委托）是什么，及实现原理？&quot;">​</a></h3><p>答：JS 事件代理就是通过给父级元素（例如：ul）绑定事件，不给子级元素(例如：li)绑定事件，然后当点击子级元素时，通过事件冒泡机制在其绑定的父元素上触发事件处理函数，主要目的是为了提升性能，因为我不用给每个子级元素绑定事件，只给父级元素绑定一次就好了,在原生 js 里面是通过 event 对象的 targe 属性实现</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> ul</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> document</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">querySelector</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;ul&quot;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#E5C07B;">ul</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">onclick</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> function</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;font-style:italic;">e</span><span style="color:#ABB2BF;">){ </span><span style="color:#7F848E;font-style:italic;">// e指event,事件对象</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">    // target获取触发事件的目标(li)</span></span>
<span class="line"><span style="color:#C678DD;">    var</span><span style="color:#E06C75;"> target</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> e</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">target</span><span style="color:#56B6C2;"> ||</span><span style="color:#E5C07B;"> e</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">srcElement</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">    // 目标(li)节点名转小写字母，不转的话是大写字母</span></span>
<span class="line"><span style="color:#C678DD;">    if</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">target</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">nodeName</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">toLowerCase</span><span style="color:#ABB2BF;">() </span><span style="color:#56B6C2;">==</span><span style="color:#98C379;"> &#39;li&#39;</span><span style="color:#ABB2BF;">){</span></span>
<span class="line"><span style="color:#61AFEF;">    	alert</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">target</span><span style="color:#ABB2BF;">.[</span><span style="color:#E06C75;">inne</span><span style="color:#ABB2BF;">](</span><span style="color:#E06C75;">https</span><span style="color:#ABB2BF;">:</span><span style="color:#7F848E;font-style:italic;">//www.zhihu.com/search?q=inne&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra={&quot;sourceType&quot;%3A&quot;answer&quot;%2C&quot;sourceId&quot;%3A2603050043})rHTML)</span></span>
<span class="line"><span style="color:#ABB2BF;">    }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>jq 方式实现相对而言简单 $(“ul”).on(“click”,“li”,function(){//事件逻辑}) 其中第二个参数指的是触发事件的具体目标，<strong>特别是给动态添加的元素绑定事件，这个特别起作用</strong></p><p>如果⼀个节点中的⼦节点是动态⽣成的，那么⼦节点需要注册事件的话应该注 册在⽗节点上</p><div class="language-html line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">ul</span><span style="color:#D19A66;"> id</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;ul&quot;</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">    &lt;</span><span style="color:#E06C75;">li</span><span style="color:#ABB2BF;">&gt;1&lt;/</span><span style="color:#E06C75;">li</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">    &lt;</span><span style="color:#E06C75;">li</span><span style="color:#ABB2BF;">&gt;2&lt;/</span><span style="color:#E06C75;">li</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">    &lt;</span><span style="color:#E06C75;">li</span><span style="color:#ABB2BF;">&gt;3&lt;/</span><span style="color:#E06C75;">li</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">    &lt;</span><span style="color:#E06C75;">li</span><span style="color:#ABB2BF;">&gt;4&lt;/</span><span style="color:#E06C75;">li</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">    &lt;</span><span style="color:#E06C75;">li</span><span style="color:#ABB2BF;">&gt;5&lt;/</span><span style="color:#E06C75;">li</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">ul</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#C678DD;">    let</span><span style="color:#E06C75;"> ul</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> document</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">querySelector</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;#ul&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E5C07B;">    ul</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">addEventListener</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;click&#39;</span><span style="color:#ABB2BF;">, (</span><span style="color:#E06C75;font-style:italic;">event</span><span style="color:#ABB2BF;">) </span><span style="color:#C678DD;">=&gt;</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E5C07B;">    	console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">event</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">target</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">    })</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>事件代理的⽅式相对于直接给⽬标注册事件来说，有以下优点</p><ul><li>节省内存</li><li>不需要给⼦节点注销事件</li></ul><h3 id="请解释什么是事件代理" tabindex="-1">请解释什么是事件代理 <a class="header-anchor" href="#请解释什么是事件代理" aria-label="Permalink to &quot;请解释什么是事件代理&quot;">​</a></h3><ul><li>事件代理（ Event Delegation ），⼜称之为事件委托。是 JavaScript 中常用绑定事件的常用技巧。顾名思义，“事件代理”即是把原本需要绑定的事件委托给⽗元素，让⽗元素担当事件监听的职务。事件代理的原理是 DOM 元素的事件冒泡。使用事件代理的好处是：可以提⾼性能</li><li>可以⼤量节省内存占用，减少事件注册，⽐如在 table 上代理所有 td 的 click 事件就⾮常棒</li><li>可以实现当新增⼦对象时⽆需再次对其绑定</li></ul><h3 id="说一下-js-数据类型有哪些" tabindex="-1">说一下 JS 数据类型有哪些？ <a class="header-anchor" href="#说一下-js-数据类型有哪些" aria-label="Permalink to &quot;说一下 JS 数据类型有哪些？&quot;">​</a></h3><p>答：JS 数据类型有：</p><p>基本数据类型：number,string,Boolean,null,undefined,symbol（ES6 新增） 复合类型：Object,function</p><h3 id="说一下-call-apply-bind-区别" tabindex="-1">说一下 call,apply,bind 区别 <a class="header-anchor" href="#说一下-call-apply-bind-区别" aria-label="Permalink to &quot;说一下 call,apply,bind 区别&quot;">​</a></h3><p>答：call,apply,bind 主要作用都是改变 this 指向的，但使用上略有区别，说一下区别:call 和 apply 的主要区别是在传递参数上不同，**call 后面传递的参数是以逗号的形式分开的，apply 传递的参数是数组形式 [Apply 是以 A 开头的,所以应该是跟 Array(数组)形式的参数]**bind 返回的是一个函数形式，如果要执行，则后面要再加一个小括号 例如：bind(obj,参数 1,参数 2,)(),bind 只能以逗号分隔形式，不能是数组形式</p><h3 id="git-相关-你们公司项目是如何管理的" tabindex="-1">git 相关：你们公司项目是如何管理的？ <a class="header-anchor" href="#git-相关-你们公司项目是如何管理的" aria-label="Permalink to &quot;git 相关：你们公司项目是如何管理的？&quot;">​</a></h3><p>答：主要通过 git 来进行项目版本控制的说几个 git 常用命令？ 答：我工作中常用的有 git add ,git status,git commit –m,git push,git pull 等说一下多人操作同一个文件，如果出现冲突该如何解决？答：当遇到多人协作修改同一个文件时出现冲突，我先将远程文件先 git pull 下来，手动修改冲突代码后，再 git add ,git commit,git push 再上传到远程仓库。如果 pull 也 pull 不下来提示冲突的话，可以先通过 git stash 暂存下来，然后再 pull 拉取，然后 git stash pop，取出原来写的，手动修改，然后提交</p><h3 id="ajax-相关" tabindex="-1">Ajax 相关 <a class="header-anchor" href="#ajax-相关" aria-label="Permalink to &quot;Ajax 相关&quot;">​</a></h3><h3 id="说一下你是如何与后端进行数据交互的" tabindex="-1">说一下你是如何与后端进行数据交互的 <a class="header-anchor" href="#说一下你是如何与后端进行数据交互的" aria-label="Permalink to &quot;说一下你是如何与后端进行数据交互的&quot;">​</a></h3><p>答：我和后端通过 ajax 来进行数据交互的，通过统一制定的接口文档，来实现前后端高效开发，如果接口文档不能详细说明，或者接口文档上的参数请求不出数据，我会主动和后端工程师沟通，直到完成跟接口相关的业务开发。当然这其中为了验证一些接口问题，会用到一些辅助工具，比方说，runapi 这种在线测试工具如果后端数据接口没有准备好，你是如何工作的 答：如果后端接口还没有准备好，我会和后端工程师沟通，通过制定接口返回数据的格式，然后前端通过一些 mock 数据的工具（上家公司使用的是 easymock,贼简单）来批量生成假数据，可以让前端和后端同时开发，而无需等待后端数据接口写好再开发，这样提升项目整体的开发效率说一下你对 ajax 的同源策略的理解 答：ajax 同源策略是因为安全的考虑，ajax 不允许访问不同域名下的资源即所谓同源策略的意思。说一下什么情况下会产生跨域及产生跨域的解决方案和实现原理？答：产生跨域的情况有：不同协议，不同域名，不同端口以及域名和 ip 地址的访问都会产生跨域。</p><h3 id="跨域的解决方案目前有三种主流解决方案" tabindex="-1">跨域的解决方案目前有三种主流解决方案 <a class="header-anchor" href="#跨域的解决方案目前有三种主流解决方案" aria-label="Permalink to &quot;跨域的解决方案目前有三种主流解决方案&quot;">​</a></h3><p>跨域是浏览器做出的限制,和后端没关系是 jsonp jsonp 实现原理：主要是利用动态创建 script 标签请求后端接口地址，然后传递 callback 参数，后端接收 callback，后端经过数据处理，返回 callback 函数调用的形式，callback 中的参数就是 json 是代理（前端代理和后端代理） 前端代理我在 vue 中主要是通过 vue 脚手架中的 config 中的 index 文件来配置的，其中有个 proxyTable 来配置跨域的是 CORSCORS 全称叫跨域资源共享，主要是后台工程师设置后端代码来达到前端跨域请求的注：现在主流框架都是用代理和 CORS 跨域实现的说一下原生 ajax 的交互过程（即流程） 答：交互流程： 先创建 XHR 对象即 XMLHttpRequest() 然后 open 准备发送，open 中有三个参数一是提交方式 get 和 post,二是接口地址，三是同步和异步 第三步是用 send 发送 第四步再发送的过程中通过 onreadystatechange 来监听接收的回调函数，可以通过判断 readyState ＝＝ 4 和 status=＝ 200 来判断是否成功返回，然后通过 responseText 接收成功返回的数据</p><h3 id="说一下你对同步和异步的理解" tabindex="-1">说一下你对同步和异步的理解 <a class="header-anchor" href="#说一下你对同步和异步的理解" aria-label="Permalink to &quot;说一下你对同步和异步的理解&quot;">​</a></h3><p>答：同步即 sync，形象的说就是代码一行行执行，前面代码和请求没有执行完，后面的代码和请求就不会被执行，缺点：容易导致代码阻塞优点：程序员容易理解（因为代码从上往下一行行执行，强调顺序）异步：即 async,形象的说就是代码可以在当前程序没有执行完，也可以执行后面的代码缺点：程序员不易理解（因为不是按顺序执行的）优点：可以解决代码阻塞问题，提升代码执行效率和性能异步解决方案主要有三个：回调函数 promise（重点掌握）generator(了解)async 和 await（重点掌握）</p><h3 id="ajax-缓存如何解决" tabindex="-1">ajax 缓存如何解决？ <a class="header-anchor" href="#ajax-缓存如何解决" aria-label="Permalink to &quot;ajax 缓存如何解决？&quot;">​</a></h3><p>答：通过在文件名后面添加随机数（也称为文件指纹）来实现，主要原理是浏览器对访问过的文件，首先会检测第二次请求的文件 url 在浏览器是否缓存过，如果缓存过就使用，否则如果是一个新的文件 url，则从服务器重新请求说一下 javaScript 原生,jQuery,vue,react,小程序 ajax 与后台交互主要用的什么技术</p><p>答：javaScript 原生 Ajax：用的是 XMLHttpRequest 对象</p><p>jQuery 中的 Ajax: $.ajax(),$.getJSON(),$.get(),$.post()等</p><p>vue 中的 Ajax:vue-resource（vue1.x 中用）,axios(主流)</p><p>微信小程序 Ajax:用的是小程序内置的 wx.request()写法和 jquery 的$.ajax()类似，参数 url,success，</p><p>data,method,fail 等</p><h3 id="说一下你对-http-状态码的了解多少" tabindex="-1">说一下你对 http 状态码的了解多少？ <a class="header-anchor" href="#说一下你对-http-状态码的了解多少" aria-label="Permalink to &quot;说一下你对 http 状态码的了解多少？&quot;">​</a></h3><p>答： 1xx（临时响应） 表示临时响应并需要请求者继续执行操作的状态代码 2xx （成功） 表示成功处理了请求的状态码。 常见的 2 开头的状态码有：200 – 服务器成功返回网页 3xx （重定向） 表示要完成请求，需要进一步操作。 通常，这些状态代码用来重定向 常见的 3 字开头的状态码有： <strong>301 （永久移动） 请求的网页已永久移动到新位置。 服务器返回此响应时，会自动将请求者转到新位置。</strong><strong>302 （临时移动） 服务器目前从不同位置的网页响应请求，但请求者应继续使用原有位置来进行以后的请求。</strong> 304 （未修改） 自从上次请求后，请求的网页未修改过。 服务器返回此响应时，不会返回网页内容。 4xx（请求错误） 这些状态代码表示请求可能出错，妨碍了服务器的处理。 常见的 4 字开头的状态有：404 – 请求的网页不存在 5xx（服务器错误） 这些状态代码表示服务器在尝试处理请求时发生内部错误。 这些错误可能是服务器本身的错误，而不是请求出错。 常见的以 5 开头的状态码有： 500 （服务器内部错误） 服务器遇到错误，无法完成请求。 503 （服务不可用） 服务器目前无法使用（由于超载或停机维护）。 通常，这只是暂时状态。</p><h3 id="你上家公司项目是前后端分离的吗" tabindex="-1">你上家公司项目是前后端分离的吗 <a class="header-anchor" href="#你上家公司项目是前后端分离的吗" aria-label="Permalink to &quot;你上家公司项目是前后端分离的吗&quot;">​</a></h3><p>答：对，是前后端分离的项目，但开始不是，开始前后端代码混在一起写的，后来重构成前后端分离的项目，方便前端和后端自己维护的代码 注：所谓前后端分离就是前后端职责明晰：后端只提供数据接口地址返回 json 数据，前端用 ajax 请求 json 数据，页面的所有业务逻辑都是前端来写，让前端控制力更强，并且减轻后端逻辑处理压力。</p><p>深拷贝，浅拷贝</p><p>用 es6 的 Object.assign({},{})进行对象合并，如果是数组可以用 es6 的 Array.from，或是 es6 的扩展运算符...arr，如果使用 es5 需要用循环来做浅拷贝，如果是深拷贝需要用递归的形式来实现.当然也可以使用 JSON.parse(JSON.stringify(对象))的方式实现深拷贝 Vue 相关：</p><h3 id="说一下-vue-最大特点是什么或者说-vue-核心是什么" tabindex="-1">说一下 vue 最大特点是什么或者说 vue 核心是什么 <a class="header-anchor" href="#说一下-vue-最大特点是什么或者说-vue-核心是什么" aria-label="Permalink to &quot;说一下 vue 最大特点是什么或者说 vue 核心是什么&quot;">​</a></h3><p>答：vue 最大特点我感觉就是“组件化“和”数据驱动“</p><p>组件化就是可以将页面和页面中可复用的元素都看做成组件，写页面的过程，就是写组件，然后页面是由这些组件“拼接“起来的组件树</p><p>数据驱动就是让我们只关注数据层，只要数据变化，页面（即视图层）会自动更新，至于如何操作 dom，完全交由 vue 去完成，咱们只关注数据，数据变了，页面自动同步变化了，很方便</p><h3 id="说一下-vue-常用基本指令有哪些" tabindex="-1">说一下 vue 常用基本指令有哪些 <a class="header-anchor" href="#说一下-vue-常用基本指令有哪些" aria-label="Permalink to &quot;说一下 vue 常用基本指令有哪些&quot;">​</a></h3><p>v-if：根据表达式的值的真假条件渲染元素。在切换时元素及它的数据绑定 / 组件被销毁并重建。 v-show：根据表达式之真假值，切换元素的 display CSS 属性。 v-for：循环指令，基于一个数组或者对象渲染一个列表，vue 2.0 以上必须需配合 key 值 使用。 v-bind：动态地绑定一个或多个特性，或一个组件 prop 到表达式。 v-on：用于监听指定元素的 DOM 事件，比如点击事件。绑定事件监听器。 v-model：实现表单输入和应用状态之间的双向绑定 v-pre：跳过这个元素和它的子元素的编译过程。可以用来显示原始 Mustache 标签。跳过大量没有指令的节点会加快编译。 v-once：只渲染元素和组件一次。随后的重新渲染，元素/组件及其所有的子节点将被视为静态内容并跳过。这可以用于优化更新性能。</p><h3 id="vue-常用的修饰符" tabindex="-1">Vue 常用的修饰符 <a class="header-anchor" href="#vue-常用的修饰符" aria-label="Permalink to &quot;Vue 常用的修饰符&quot;">​</a></h3><p>v-on 指令常用修饰符： .stop - 调用 event.stopPropagation()，禁止事件冒泡。 .prevent - 调用 event.preventDefault()，阻止事件默认行为。 .capture - 添加事件侦听器时使用 capture 模式。 .self - 只当事件是从侦听器绑定的元素本身触发时才触发回调。 .{keyCode | keyAlias} - 只当事件是从特定键触发时才触发回调。 .native - 监听组件根元素的原生事件。 .once - 只触发一次回调。 .left - (2.2.0) 只当点击鼠标左键时触发。 .right - (2.2.0) 只当点击鼠标右键时触发。 .middle - (2.2.0) 只当点击鼠标中键时触发。 .passive - (2.3.0) 以 { passive: true } 模式添加侦听器</p><p>注意： 如果是在自己封装的组件或者是使用一些第三方的 UI 库时，会发现并不起效果，这时就需要用\`·.native 修饰符了，如：</p><div class="language-vue line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">//使用示例：</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">el-input</span></span>
<span class="line"><span style="color:#D19A66;">	v-model</span><span style="color:#ABB2BF;">=</span><span style="color:#ABB2BF;">&quot;</span><span style="color:#E06C75;">inputName</span><span style="color:#ABB2BF;">&quot;</span></span>
<span class="line"><span style="color:#D19A66;">	placeholder</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;搜索你的文件&quot;</span></span>
<span class="line"><span style="color:#ABB2BF;">	@</span><span style="color:#D19A66;">keyup</span><span style="color:#ABB2BF;">.enter.</span><span style="color:#D19A66;">native</span><span style="color:#ABB2BF;">=</span><span style="color:#ABB2BF;">&quot;</span><span style="color:#61AFEF;">searchFile</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">params</span><span style="color:#ABB2BF;">)</span><span style="color:#ABB2BF;">&quot;</span></span>
<span class="line"><span style="color:#D19A66;">	\\</span></span>
<span class="line"><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">el-input</span><span style="color:#ABB2BF;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>v-bind 指令常用修饰符：</p><p>.prop - 被用于绑定 DOM 属性 (property)。(差别在哪里？)</p><p>.camel - (2.1.0+) 将 kebab-case 特性名转换为 camelCase. (从 2.1.0 开始支持)</p><p>.sync (2.3.0+) 语法糖，会扩展成一个更新父组件绑定值的 v-on 侦听器。</p><p>v-model 指令常用修饰符：</p><p>.lazy - 取代 input 监听 change 事件</p><p>.number - 输入字符串转为数字</p><p>.trim - 输入首尾空格过滤</p><h3 id="vue-组件中-data-为什么必须是函数" tabindex="-1">Vue 组件中 data 为什么必须是函数 <a class="header-anchor" href="#vue-组件中-data-为什么必须是函数" aria-label="Permalink to &quot;Vue 组件中 data 为什么必须是函数&quot;">​</a></h3><p>问题一：Vue 组件中 data 为什么必须是函数？</p><p>简单回答</p><p>//为什么 data 函数里面要 return 一个对象</p><div class="language-vue line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#C678DD;">export</span><span style="color:#C678DD;"> default</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#61AFEF;">	data</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#C678DD;">		return</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">			// 返回一个唯一的对象，不要和其他组件共用一个对象进行返回</span></span>
<span class="line"><span style="color:#E06C75;">			menu</span><span style="color:#ABB2BF;">: </span><span style="color:#E5C07B;">MENU</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">data</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#E06C75;">			poi</span><span style="color:#ABB2BF;">: </span><span style="color:#E5C07B;">POILIST</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">data</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">		};</span></span>
<span class="line"><span style="color:#ABB2BF;">	},</span></span>
<span class="line"><span style="color:#ABB2BF;">};</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>因为一个组件是可以共享的，但他们<strong>的 data 是私有的，所以每个组件都要 return 一个新的 data 对象，返回一个唯一的对象，不要和其他组件共用一个对象</strong>。</p><h3 id="说一下-v-if-和-v-show-的区别" tabindex="-1">说一下 v-if 和 v-show 的区别 <a class="header-anchor" href="#说一下-v-if-和-v-show-的区别" aria-label="Permalink to &quot;说一下 v-if 和 v-show 的区别&quot;">​</a></h3><p>答：v-if 和 v-show 都可以显示和隐藏一个元素，但有本质区别</p><p>v-if 是惰性的，只是值为 false 就不会加载对应元素，为 true 才动态加载对应元素 v-show:是无论为 true 和为 false 都会加载对应 html 代码，但为 false 时用 display:none 隐藏不在页面显示，但为 true 时页面上用 display:block 显示其效果 适用场景：切换频繁的场合用 v-show,切换不频繁的场合用 v-if</p><h3 id="说一下-vue-自定义指令如何实现的和适用场景" tabindex="-1">说一下 vue 自定义指令如何实现的和适用场景？ <a class="header-anchor" href="#说一下-vue-自定义指令如何实现的和适用场景" aria-label="Permalink to &quot;说一下 vue 自定义指令如何实现的和适用场景？&quot;">​</a></h3><p>答：哦，这个问题是这样的，vue 除有了 v-for,v-if 等自带 vue 指令外,但不能满足所有的开发需求，有时需要自定义指令，自定义指令创建有全局自定义指令和局部自定义指令 全局自定义指令：Vue.directive(‘指令名’,{ inserted(el) { } }) 局部自定义指令：directives:</p><h3 id="说一下-vue-过滤器做什么的-vue1-x-和-vue2-x-这块的区别" tabindex="-1">说一下 vue 过滤器做什么的(vue1.x 和 vue2.x 这块的区别) <a class="header-anchor" href="#说一下-vue-过滤器做什么的-vue1-x-和-vue2-x-这块的区别" aria-label="Permalink to &quot;说一下 vue 过滤器做什么的(vue1.x 和 vue2.x 这块的区别)&quot;">​</a></h3><p>答：<strong>vue 过滤器主要用于对渲染出来的数据进行格式化处理</strong>。例如：后台返回的数据性别用 0 和 1 表示，但渲染到页面上不能是 0 和 1 我得转换为“男“和”女”，这时就会用到过滤器，还有商品价格读取出来的是普通数值，例如：230035,但我要在前面加个货币符号和千分分隔等，例如变成：￥ 230，035,都得需要 vue 过滤器 如何创建过滤器呢，跟创建自定义指令类似，也有全局和局部过滤器的形式 <strong>全局过滤器</strong>：Vue.filter(‘过滤器名’,function(参数 1,参数 2,…) { //……….. return 要返回的数据格式 }) <strong>局部过滤器</strong>：在组件内部添加 filters 属性来定义过滤器 fitlers:{ 过滤器名(参数 1,参数 2,,…参数 n) { //……….. return 要返回的数据格式 } }</p><h3 id="说一下-vue-生命周期钩子函数有哪些-分别什么时候触发" tabindex="-1">说一下 vue 生命周期钩子函数有哪些，分别什么时候触发 <a class="header-anchor" href="#说一下-vue-生命周期钩子函数有哪些-分别什么时候触发" aria-label="Permalink to &quot;说一下 vue 生命周期钩子函数有哪些，分别什么时候触发&quot;">​</a></h3><p>答：vue 生命周期即为一个组件从出生到死亡的一个完整周期，主要包括以下<strong>4 个阶段：创建，挂载，更新，销毁</strong> 创建前：beforeCreate, 创建后:created 挂载前：beforeMount, 挂载后：mounted 更新前：beforeUpdate, 更新后：updated 销毁前：beforeDestroy, 销毁后：destroyed 我平时用的比较多的钩了是 created 和 mounted，created 用于获取后台数据，mounted 用于 dom 挂载完后做一些 dom 操作,以及初始化插件等.beforeDestroy 用户清除定时器以及解绑事件等, 另外还新增了使用内置组件 keep-alive 来缓存实例，而不是频繁创建和销毁(开销大) actived 实例激活 deactived 实例失效 以下为详解版,大家理解就 ok: 生命周期钩子函数（11 个）Function（类型），标注蓝色的那个是属于类型的意思。 beforeCreateFunction 在实例初始化之后，数据观测 (data observer) 和 event/watcher 事件配置之前被调用。 createdFunction 在实例创建完成后被立即调用。在这一步，实例已完成以下的配置：数据观测 (data observer)， 属性和方法的运算，watch/event 事件回调。然而，挂载阶段还没开始，$el 属性目前不可见。 beforeMountFunction在挂载开始之前被调用：相关的 render 函数首次被调用。 mountedFunctionel 被新创建的 vm.$el 替换，并挂载到实例上去之后调用该钩子。如果 root 实例挂载了一个文档内元素，当 mounted 被调用时 vm.$el 也在文档内。 beforeUpdateFunction 数据更新时调用，发生在虚拟 DOM 打补丁之前。这里适合在更新之前访问现有的 DOM，比如手动移除已添加的事件监听器。该钩子在服务器端渲染期间不被调用，因为只有初次渲染会在服务端进行。 updatedFunction 由于数据更改导致的虚拟 DOM 重新渲染和打补丁，在这之后会调用该钩子。 activatedFunctionkeep-alive 组件激活时调用。该钩子在服务器端渲染期间不被调用。 deactivatedFunctionkeep-alive 组件停用时调用。该钩子在服务器端渲染期间不被调用。 beforeDestroyFunction 实例销毁之前调用。在这一步，实例仍然完全可用。该钩子在服务器端渲染期间不被调用。 destroyedFunctionVue 实例销毁后调用。调用后，Vue 实例指示的所有东西都会解绑定，所有的事件监听器会被移除，所有的子实例也会被销毁。该钩子在服务器端渲染期间不被调用。 errorCaptured（2.5.0+ 新增）(err: Error, vm: Component, info: string) =&gt; ?boolean 当捕获一个来自子孙组件的错误时被调用。此钩子会收到三个参数：错误对象、发生错误的组件实例以及一个包含错误来源信息的字符串。此钩子可以返回 false 以阻止该错误继续向上传播。</p><h3 id="说一下-vue-组件通讯-即传值-有哪几种形式-分别是如何实现的" tabindex="-1">说一下 vue 组件通讯（即传值）有哪几种形式，分别是如何实现的 <a class="header-anchor" href="#说一下-vue-组件通讯-即传值-有哪几种形式-分别是如何实现的" aria-label="Permalink to &quot;说一下 vue 组件通讯（即传值）有哪几种形式，分别是如何实现的&quot;">​</a></h3><p>答：vue 组件通讯大致有三种：父传子，子传父，还有兄弟之间通讯</p><p><strong>第一种：父传子：主要通过 props 来实现的</strong> 具体实现：父组件通过 import 引入子组件，并注册，在子组件标签上添加要传递的属性，子组件通过 props 接收，接收有两种形式一是通过数组形式[‘要接收的属性’ ]，二是通过对象形式{ }来接收，对象形式可以设置要传递的数据类型和默认值，而数组只是简单的接收 <strong>第二种：子传父：主要通过$emit 来实现</strong> 具体实现：子组件通过通过绑定事件触发函数，在其中设置 this.$emit(‘要派发的自定义事件’，要传递的值)，$emit 中有两个参数一是要派发的自定义事件，第二个参数是要传递的值 然后父组件中,在这个子组件身上@派发的自定义事件,绑定事件触发的 methods 中的方法接受的默认值,就是传递过来的参数 <strong>第三种：兄弟之间传值有两种方法：</strong> 方法一：通过 event bus 实现 具体实现:创建一个空的 vue 并暴露出去，这个作为公共的 bus,即当作两个组件的桥梁，在两个兄弟组件中分别引入刚才创建的 bus，在组件 A 中通过 bus.$emit（’自定义事件名’，要发送的值）发送数据，在组件B中通过bus.$on（‘自定义事件名‘,function(v) { //v 即为要接收的值 }）接收数据 方法二：通过 vuex 实现 具体实现：vuex 是一个状态管理工具，主要解决大中型复杂项目的数据共享问题，主要包括 state,actions,mutations,getters 和 modules 5 个要素，主要流程：组件通过 dispatch 到 actions，actions 是异步操作，再 actions 中通过 commit 到 mutations，mutations 再通过逻辑操作改变 state，从而同步到组件，更新其数据状态</p><h3 id="说一下-vue-封装组件中的-slot-作用" tabindex="-1">说一下 vue 封装组件中的 slot 作用 <a class="header-anchor" href="#说一下-vue-封装组件中的-slot-作用" aria-label="Permalink to &quot;说一下 vue 封装组件中的 slot 作用&quot;">​</a></h3><p>答：vue 封装组件涉及三个东西: 一是事件(v-on,$emit)， 二是传参通过 props 三是 slot：slot 作用主要是可以实现内容分发，组件标签内嵌套内容，可通过<code>&lt;slot&gt;&lt;/slot&gt;</code>来定义占位的内容 分为具名的 slot 和匿名的 slot 在编写可复用组件的时候，时刻考虑组件是否可复用是有好处的。一次性组件跟其他组件紧密耦合没关系，但是可复用组件一定要定义一个清晰的公开接口。 Vue.js 组件 API 来自 三部分：prop、事件、slot： <strong>prop 允许外部环境传递数据给组件</strong>，在 vue-cli 工程中也可以使用 vuex 等传递数据。 <strong>事件允许组件触发外部环境的 action(就是行为,也就是方法的意思)</strong> **slot 允许外部环境将内容插入到组件的视图结构内。****说一下 vue 转场动画如何实现的** 答：vue 转场动画主要通过 vue 中的提供的 transition 组件实现的，例如；</p><div class="language-vue line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">transition</span><span style="color:#D19A66;"> name</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;名称&quot;</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">    &lt;router-view&gt;&lt;/router-view&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">transition</span><span style="color:#ABB2BF;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>其中 name 为转场的名称，自己定义，可通过定义进入和离开两种转场动画，格式为： .名称-enter ｛ ｝ //将要进入动画 .名称-enter-active { } //定义进入的过程动画 .名称-leave { } //将要离开的动画 .名称-leave-active { } //定义离开过程中的动画</p><h3 id="说一下你对单向数据流的理解" tabindex="-1">说一下你对单向数据流的理解 <a class="header-anchor" href="#说一下你对单向数据流的理解" aria-label="Permalink to &quot;说一下你对单向数据流的理解&quot;">​</a></h3><p>答：<strong>单向数据流</strong>主要是 vue 组件间传递数据是单向的，即数据总是由父组件传递给子组件，子组件在其内部维护自己的数据，但它无权修改父组件传递给它的数据，当开发者尝试这样做的时候，vue 将会报错。这样做是为了组件间更好的维护。 在开发中可能有多个子组件依赖于父组件的某个数据，假如子组件可以修改父组件数据的话，一个子组件变化会引发所有依赖这个数据的子组件发生变化，所以 vue 不推荐子组件修改父组件的数据</p><h3 id="说一下-vue-双向数据绑定的原理" tabindex="-1">说一下 vue 双向数据绑定的原理 <a class="header-anchor" href="#说一下-vue-双向数据绑定的原理" aria-label="Permalink to &quot;说一下 vue 双向数据绑定的原理&quot;">​</a></h3><p>答：核心主要利用 ES5 中的 Object.defineProperty 实现的，然后利用里面的 getter 和 setter 来实现双向数据绑定的，大致就这些，其实要实现起来比这个要复杂一些，不过我大致了解过。</p><h3 id="说一下-vue-路由或前端路由实现原理" tabindex="-1">说一下 vue 路由或前端路由实现原理 <a class="header-anchor" href="#说一下-vue-路由或前端路由实现原理" aria-label="Permalink to &quot;说一下 vue 路由或前端路由实现原理&quot;">​</a></h3><p>答：前端路由实现原理主要通过以下两种技术实现的 第一种：利用 H5 的 history API 实现 主要通过 history.pushState 和 history.replaceState 来实现，不同之处在于，pushState 会增加一条新的历史记录，而 replaceState 则会替换当前的历史记录[发布项目时,需要配置下 apache] 第二种：利用 url 的 hash 实现 我们经常在 url 中看到 #，这个 # 有两种情况，一个是我们所谓的锚点，路由里的 # 不叫锚点，我们称之为 hash，我们说的就是 hash,主要利用监听哈希值的变化来触发事件 —— hashchange 事件来做页面局部更新 总结：hash 方案兼容性好，而 H5 的 history 主要针对高级浏览器。 以下为具体的 API 的区别: this.$router.push(location, onComplete?, onAbort?)这个方法会向 history 栈添加一个新的记录，所以，当用户点击浏览器后退按钮时，则回到之前的 URL。并且点击 <code>&lt;router-link :to=&quot;...&quot;&gt;</code>等同于调用 router.push(...)。 this.$router.replace(location, onComplete?, onAbort?)这个方法不会向 history 添加新记录，而是跟它的方法名一样 —— 替换掉当前的 history 记录，所以，当用户点击浏览器后退按钮时，并不会回到之前的 URL。 this.$router.go(n)这个方法的参数是一个整数，意思是在 history 记录中向前或者后退多少步，类似 window.history.go(n)。 以上也可能会形成一个新的面试题:<strong>replace和push的区别</strong><strong>可以说,以前在一个项目里面配置了一个二级路由,里面有tab切换部分(详情,评价,说明),因为返回上一页的时候,不能在这几个选项卡之间来回切换.所以我使用了this.$router.replace 方法,不计入 history 记录中,所以不会出现,反复切换的 bug*</strong>*说一下 vue 路由钩子（或称 vue 路由守卫）的理解** 什么场景下用到 答：vue 路由钩子是在路由跳转过程中拦截当前路由和要跳转的路由的信息，有三种路由钩子： 第一种：全局路由钩子 beforeEach(to,from,next) { } 第二种：路由独享的钩子 beforeEnter(to,from,next) { } 第三种：组件内的钩子 beforeRouteEnter(to,from,next) { //… } beforeRouteUpdate(to,from,next) { //… } beforeRouteLeave(to,from,next) { //… } 适用场景：动态设置页面标题，判断用户登录权限等:代码示例: //全局路由导航守卫 vueRouter.beforeEach(function (to, from, next) { const nextRoute = [ &#39;detail&#39;]; const auth = sessionStorage.getItem(&quot;username&quot;); let FROMPATH = from.path; //跳转至上述 3 个页面 if (nextRoute.indexOf(to.name) &gt;= 0) { //上述数组中的路径，是相当于有权限的页面，访问数组列表中的页面就应该是在登陆状态下 if (!auth) { let params = Object.assign({frompath:FROMPATH},from.query); next({path: &#39;/newlogin&#39;,query:params}); } } //已登录的情况再去登录页，跳转至首页 if (to.name === &#39;newlogin&#39;) { if (auth) { // vueRouter.push({name: &#39;index&#39;}); next({path: &#39;/&#39;}); } } next(); });</p><h3 id="说一下-vue-路由懒加载解决什么问题的" tabindex="-1">说一下 vue 路由懒加载解决什么问题的? <a class="header-anchor" href="#说一下-vue-路由懒加载解决什么问题的" aria-label="Permalink to &quot;说一下 vue 路由懒加载解决什么问题的?&quot;">​</a></h3><p>答：vue 路由懒加载主要解决打包后文件过大的问题，事件触发才加载对应组件中的 js<strong>说一下如何解决 vue 首屏加载慢或白屏？</strong> 答： 1.路由懒加载 <img src="`+l+'" alt="img"> 2.开启 Gzip 压缩 <img src="'+o+'" alt="img"> \\3. 使用 webpack 的 externals 属性把不需要打包的库文件分离出去，减少打包后文件的大小 <img src="'+p+'" alt="img"> \\4. 使用 vue 的服务端渲染(SSR)</p><h3 id="说一下-vue-开发环境和线上环境如何切换" tabindex="-1">说一下 vue 开发环境和线上环境如何切换 <a class="header-anchor" href="#说一下-vue-开发环境和线上环境如何切换" aria-label="Permalink to &quot;说一下 vue 开发环境和线上环境如何切换&quot;">​</a></h3><p>答：主要通过检测 process.env.NODE_ENV===”production”和 process.env.NODE_ENV===”development”环境，来设置线上和线下环境地址，从而实现线上和线下环境地址的切换</p><h3 id="说一下你们项目中-vue-如何跨域的" tabindex="-1">说一下你们项目中 vue 如何跨域的 <a class="header-anchor" href="#说一下你们项目中-vue-如何跨域的" aria-label="Permalink to &quot;说一下你们项目中 vue 如何跨域的&quot;">​</a></h3><p>答：跨域前端和后端都可以实现，如果只针对 vue,vue 本身可以通过代理的方式可以实现，具体实现：</p><p>在 config 中的 index.js 中配置 proxy 来实现：</p><p><img src="'+t+'" alt="img"></p><h3 id="说一下-vue-中-methods-computed-watch-的区别" tabindex="-1">说一下 vue 中 methods,computed,watch 的区别 <a class="header-anchor" href="#说一下-vue-中-methods-computed-watch-的区别" aria-label="Permalink to &quot;说一下 vue 中 methods,computed,watch 的区别&quot;">​</a></h3><p>答：methods 中都是封装好的函数，无论是否有变化只要触发就会执行 computed:是 vue 独有的特性计算属性，可以对 data 中的依赖项再重新计算，得到一个新值，应用到视图中，和 methods 本质区别是 computed 是可缓存的，也就是说 computed 中的依赖项没有变化，则 computed 中的值就不会重新计算，而 methods 中的函数是没有缓存的。Watch 是监听 data 和计算属性中的新旧变化。 vue 用什么绑定事件，用什么绑定属性 答：用 v-on 绑定事件，简称：@,用 v-bind 来绑定属性，简称：:属性</p><h3 id="vue-如何动态添加属性-实现数据响应" tabindex="-1">vue 如何动态添加属性，实现数据响应？ <a class="header-anchor" href="#vue-如何动态添加属性-实现数据响应" aria-label="Permalink to &quot;vue 如何动态添加属性，实现数据响应？&quot;">​</a></h3><p>答：vue 主要通过用 this.$set(对象，‘属性‘，值)实现动态添加属性，以实现数据的响应注意是添加,我记忆中如果是修改引用类型属性的值,是可以自动渲染的.</p><h3 id="vue-中的-http-请求是如何管理的" tabindex="-1">vue 中的 http 请求是如何管理的 <a class="header-anchor" href="#vue-中的-http-请求是如何管理的" aria-label="Permalink to &quot;vue 中的 http 请求是如何管理的&quot;">​</a></h3><p>答：vue 中的 http 请求如果散落在 vue 各种组件中，不便于后期维护与管理，所以项目中通常将业务需求统一存放在一个目录下管理，例如 src 下的 API 文件夹，这里面放入组件中用到的所有封装好的 http 请求并导出，再其他用到的组件中导入调用。如下面封装的 HTTP 请求 <img src="'+r+'" alt="img">说一下你对 axios 拦截器的理解： 答：axios 拦截器可以让我们在项目中对后端 http 请求和响应自动拦截处理，减少请求和响应的代码量，提升开发效率同时也方便项目后期维护 例如： <img src="'+c+'" alt="img"><img src="'+i+'" alt="img"> 或者对公共的数据做操作 <img src="'+u+'" alt="img">*说一下 vue 和 jquey 的区别** 答：jquery 主要是玩 dom 操作的“神器“，强大的选择器,封装了好多好用的 dom 操作方法和如何获取 ajax 方法 例如：$.ajax（）非常好用 vue:主要用于数据驱动和组件化，很少操作 dom，当然 vue 可能通过 ref 来选择一个 dom 或组件</p><h3 id="说一下-vue-如何实现局部样式的或者说如何实现组件之间样式不冲突的和实现原理是什么" tabindex="-1">说一下 vue 如何实现局部样式的或者说如何实现组件之间样式不冲突的和实现原理是什么？ <a class="header-anchor" href="#说一下-vue-如何实现局部样式的或者说如何实现组件之间样式不冲突的和实现原理是什么" aria-label="Permalink to &quot;说一下 vue 如何实现局部样式的或者说如何实现组件之间样式不冲突的和实现原理是什么？&quot;">​</a></h3><p>答：css 没有局部样式的概念，vue 脚手架通过实现了，即在 style 标签上添加 scoped <img src="'+B+'" alt="img"> scoped 的实现原理：vue 通过 postcss 给每个 dom 元素添加一个以 data-开头的随机自定义属性实现的</p><h3 id="说一下-vue-第三方-ui-样式库如何实现样式穿透的-ui-库和-less-sass-穿透问题-deep" tabindex="-1">说一下 vue 第三方 ui 样式库如何实现样式穿透的（ui 库和 less/sass 穿透问题） &gt;&gt;&gt; /deep/ <a class="header-anchor" href="#说一下-vue-第三方-ui-样式库如何实现样式穿透的-ui-库和-less-sass-穿透问题-deep" aria-label="Permalink to &quot;说一下 vue 第三方 ui 样式库如何实现样式穿透的（ui 库和 less/sass 穿透问题） &gt;&gt;&gt; /deep/&quot;">​</a></h3><p><img src="'+d+'" alt="img"><strong>vue 目录结构（面试时可能会这样问说一下 vue 工程目录结构）</strong>：这个了解下就可以 答：统一的目录结构可以方便团队协作和职责明晰，也方便项目后期维护和管理，具体 vue 项目目录结构包括： build:项目构建目录 config:项目配置，包括代理配置，线上和线下环境配置 node_modules:node 包目录，npm install 安装的包都在这个目录 src:平时开发时的目录 static:存入一些静态资源资源目录，我们可以把一些图片，字体，json 数据放在这里。 .eslintrc.js：Eslint 代码检查配置文件 .babelrc:ES6 配置 .gitignore:忽略提交到远程仓库的配置</p><h3 id="vue-脚手架是你们公司搭建的-还是用的-vue-的脚本架-webpack-了解多少" tabindex="-1">vue 脚手架是你们公司搭建的，还是用的 vue 的脚本架？webpack 了解多少？ <a class="header-anchor" href="#vue-脚手架是你们公司搭建的-还是用的-vue-的脚本架-webpack-了解多少" aria-label="Permalink to &quot;vue 脚手架是你们公司搭建的，还是用的 vue 的脚本架？webpack 了解多少？&quot;">​</a></h3><p>答：我们公司用的 vue 官方的脚手架（vue-cli）,vue-cli 版本有 3.0 和 2.9.x 版本 webpack 是一个前端模块化打包构建工具，vue 脚手架本身就用的 webpack 来构建的，webpack 本身需要的入口文件通过 entry 来指定，出口通过 output 来指定，默认只支持 js 文件，其他文件类型需要通过对应的 loader 来转换，例如：less 需要 less,less-loader,sass 需要 sass-loader,css 需要 style-loader,css-loader 来实现。当然本身还有一些内置的插件来对文件进行压缩合并等操作</p><h3 id="说一下你对-vuex-的理解" tabindex="-1">说一下你对 vuex 的理解 <a class="header-anchor" href="#说一下你对-vuex-的理解" aria-label="Permalink to &quot;说一下你对 vuex 的理解&quot;">​</a></h3><p>答：vuex 是一个状态管理工具，主要解决大中型复杂项目的数据共享问题，主要包括 state,actions,mutations,getters 和 modules 5 个要素，主要流程：组件通过 dispatch 到 actions，actions 是异步操作，再 actions 中通过 commit 到 mutations，mutations 再通过逻辑操作改变 state，从而同步到组件，更新其数据状态,而 getters 相当于组件的计算属性对,组件中获取到的数据做提前处理的.再说到辅助函数的作用.</p><h3 id="vuex-如何实现数据持久化-即刷新后数据还保留" tabindex="-1">vuex 如何实现数据持久化（即刷新后数据还保留）？ <a class="header-anchor" href="#vuex-如何实现数据持久化-即刷新后数据还保留" aria-label="Permalink to &quot;vuex 如何实现数据持久化（即刷新后数据还保留）？&quot;">​</a></h3><p>答：因为 vuex 中的 state 是存储在内存中的，一刷新就没了，例如登录状态，解决方案有： 第一种：利用 H5 的本地存储(localStorage,sessionStorage) 第二种：利用第三方封装好的插件，例如：vuex-persistedstate <img src="'+y+'" alt="img"></p><h3 id="说一下-nexttick-的作用和使用场景" tabindex="-1">说一下 nextTick 的作用和使用场景 <a class="header-anchor" href="#说一下-nexttick-的作用和使用场景" aria-label="Permalink to &quot;说一下 nextTick 的作用和使用场景&quot;">​</a></h3><p>答：vue 中的 nextTick 主要用于处理数据动态变化后，DOM 还未及时更新的问题，用 nextTick 就可以获取数据更新后最新 DOM 的变化适用场景：第一种：有时需要根据数据动态的为页面某些 dom 元素添加事件，这就要求在 dom 元素渲染完毕时去设置，但是 created 与 mounted 函数执行时一般 dom 并没有渲染完毕，所以就会出现获取不到，添加不了事件的问题，这回就要用到 nextTick 处理第二种：在使用某个第三方插件时 ，希望在 vue 生成的某些 dom 动态发生变化时重新应用该插件，也会用到该方法，这时候就需要在 $nextTick 的回调函数中执行重新应用插件的方法，例如:应用滚动插件better-scroll时<img src="'+h+'" alt="img"><img src="'+b+`" alt="img">第三种：数据改变后获取焦点**再来看以下解析:**何为$nextTick？简单回答：因为 Vue 的异步更新队列，$nextTick 是用来知道什么时候 DOM 更新完成的。详细解读：我们先来看这样一个场景：有一个 div，默认用 v-if 将它隐藏，点击一个按钮后，改变 v-if 的值，让它显示出来，同时拿到这个 div 的文本内容。如果 v-if 的值是 false，直接去获取 div 内容是获取不到的，因为此时 div 还没有被创建出来，那么应该在点击按钮后，改变 v-if 的值为 true，div 才会被创建，此时再去获取，示例代码如下：</p><div class="language-html line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">div</span><span style="color:#D19A66;"> id</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;app&quot;</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">	&lt;</span><span style="color:#E06C75;">div</span><span style="color:#D19A66;"> id</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;div&quot;</span><span style="color:#D19A66;"> v-if</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;showDiv&quot;</span><span style="color:#ABB2BF;">&gt;这是一段文本&lt;/</span><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">	&lt;</span><span style="color:#E06C75;">button</span><span style="color:#D19A66;"> @click</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;getText&quot;</span><span style="color:#ABB2BF;">&gt;获取div内容&lt;/</span><span style="color:#E06C75;">button</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#C678DD;">	var</span><span style="color:#E06C75;"> app</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> Vue</span><span style="color:#ABB2BF;">({</span></span>
<span class="line"><span style="color:#E06C75;">		el</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;#app&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#E06C75;">		data</span><span style="color:#ABB2BF;">: { </span><span style="color:#E06C75;">showDiv</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">false</span><span style="color:#ABB2BF;"> },</span></span>
<span class="line"><span style="color:#E06C75;">		methods</span><span style="color:#ABB2BF;">: {</span></span>
<span class="line"><span style="color:#61AFEF;">			getText</span><span style="color:#ABB2BF;">: </span><span style="color:#C678DD;">function</span><span style="color:#ABB2BF;"> () {</span></span>
<span class="line"><span style="color:#E5C07B;">				this</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">showDiv</span><span style="color:#56B6C2;"> =</span><span style="color:#D19A66;"> true</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#C678DD;">				var</span><span style="color:#E06C75;"> text</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> document</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">getElementById</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;div&quot;</span><span style="color:#ABB2BF;">).</span><span style="color:#E06C75;">innnerHTML</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E5C07B;">				console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">text</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">			},</span></span>
<span class="line"><span style="color:#ABB2BF;">		},</span></span>
<span class="line"><span style="color:#ABB2BF;">	});</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>这段代码并不难理解，但是运行后在控制台会抛出一个错误：Cannot read property &#39;innnerHTML of null，意思就是获取不到 div 元素。这里就涉及 Vue 一个重要的概念：异步更新队列。异步更新队列<strong>Vue 在观察到数据变化时并不是直接更新 DOM，而是开启一个队列，并缓冲在同一个事件循环中发生的所以数据改变。在缓冲时会去除重复数据，从而避免不必要的计算和 DOM 操作。然后，在下一个事件循环 tick 中，Vue 刷新队列并执行实际（已去重的）工作</strong>。</p><p>所以如果你用一个 for 循环来动态改变数据 100 次，其实它只会应用最后一次改变，如果没有这种机制，DOM 就要重绘 100 次，这固然是一个很大的开销。Vue 会根据当前浏览器环境优先使用原生的 Promise.then 和 MutationObserver，如果都不支持，就会采用 setTimeout 代替。</p><p>知道了 Vue 异步更新 DOM 的原理，上面示例的报错也就不难理解了。事实上，在执行 this.showDiv = true 时，div 仍然还是没有被创建出来，直到下一个 vue 事件循环时，才开始创建。</p><p><strong>$nextTick 就是用来知道什么时候 DOM 更新完成的</strong>，所以上面的示例代码需要修改为：</p><div class="language-html line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">div</span><span style="color:#D19A66;"> id</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;app&quot;</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">	&lt;</span><span style="color:#E06C75;">div</span><span style="color:#D19A66;"> id</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;div&quot;</span><span style="color:#D19A66;"> v-if</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;showDiv&quot;</span><span style="color:#ABB2BF;">&gt;这是一段文本&lt;/</span><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">	&lt;</span><span style="color:#E06C75;">button</span><span style="color:#D19A66;"> @click</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;getText&quot;</span><span style="color:#ABB2BF;">&gt;获取div内容&lt;/</span><span style="color:#E06C75;">button</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#C678DD;">	var</span><span style="color:#E06C75;"> app</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> Vue</span><span style="color:#ABB2BF;">({</span></span>
<span class="line"><span style="color:#E06C75;">		el</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;#app&quot;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#E06C75;">		data</span><span style="color:#ABB2BF;">: { </span><span style="color:#E06C75;">showDiv</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">false</span><span style="color:#ABB2BF;"> },</span></span>
<span class="line"><span style="color:#E06C75;">		methods</span><span style="color:#ABB2BF;">: {</span></span>
<span class="line"><span style="color:#61AFEF;">			getText</span><span style="color:#ABB2BF;">: </span><span style="color:#C678DD;">function</span><span style="color:#ABB2BF;"> () {</span></span>
<span class="line"><span style="color:#E5C07B;">				this</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">showDiv</span><span style="color:#56B6C2;"> =</span><span style="color:#D19A66;"> true</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E5C07B;">				this</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">$nextTick</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">function</span><span style="color:#ABB2BF;"> () {</span></span>
<span class="line"><span style="color:#C678DD;">					var</span><span style="color:#E06C75;"> text</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> document</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">getElementById</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;div&quot;</span><span style="color:#ABB2BF;">).</span><span style="color:#E06C75;">innnerHTML</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E5C07B;">					console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">text</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">				});</span></span>
<span class="line"><span style="color:#ABB2BF;">			},</span></span>
<span class="line"><span style="color:#ABB2BF;">		},</span></span>
<span class="line"><span style="color:#ABB2BF;">	});</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p>这时再点击事件，控制台就打印出 div 的内容“这是一段文本“了。</p><p>理论上，我们应该不用去主动操作 DOM，因为 Vue 的核心思想就是数据驱动 DOM，但在很多业务里，我们避免不了会使用一些第三方库，比如 popper.js、swiper 等，这些基于原生 javascript 的库都有创建和更新及销毁的完整生命周期，与 Vue 配合使用时，就要利用好$nextTick。</p><p><strong>v-for 与 v-if 的优先级</strong>当它们处于同一节点，<strong>v-for 的优先级比 v-if 更高</strong>，这意味着 v-if 将分别重复运行于每个 v-for 循环中。当你想为仅有的一些项渲染节点时，这种优先级的机制会十分有用，如下：</p><div class="language-html line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">li</span><span style="color:#D19A66;"> v-for</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;todo in todos&quot;</span><span style="color:#D19A66;"> v-if</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;!todo.isComplete&quot;</span><span style="color:#ABB2BF;">&gt;{{ todo }}&lt;/</span><span style="color:#E06C75;">li</span><span style="color:#ABB2BF;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>上面的代码只传递了未完成的 todos。而如果你的目的是有条件地跳过循环的执行，那么可以将 v-if 置于外层元素 (或<code>&lt;template&gt;</code>)上 vue 中 keep-alive 组件的作用<strong>keep-alive：主要用于保留组件状态或避免重新渲染。</strong></p><p>比如： 有一个列表页面和一个 详情页面，那么用户就会经常执行打开详情=&gt;返回列表=&gt;打开详情这样的话 列表 和 详情 都是一个频率很高的页面，那么就可以对列表组件使用<code>&lt;keep-alive&gt;&lt;/keep-alive&gt;</code>进行缓存，这样用户每次返回列表的时候，都能从缓存中快速渲染，而不是重新渲染。</p><p>1、属性：include:字符串或正则表达式。只有匹配的组件会被缓存。</p><p>exclude：字符串或正则表达式。任何匹配的组件都不会被缓存。</p><p>2、用法：包裹动态组件时，会缓存不活动的组件实例，而不是销毁它们。和<code>&lt;transition&gt;</code>相似，<code>&lt;keep-alive&gt;</code>是一个抽象组件：它自身不会渲染一 DOM 元素，也不会出现在父组件链中。当组件在<code>&lt;keep-alive&gt;</code> 内被切换，在 2.2.0 及其更高版本中，</p><p><strong>activated 和 deactivated 生命周期 将会在 树内的所有嵌套组件中触发</strong>。</p><h3 id="css-相关" tabindex="-1">CSS 相关 <a class="header-anchor" href="#css-相关" aria-label="Permalink to &quot;CSS 相关&quot;">​</a></h3><h3 id="css3-新增特性有哪些" tabindex="-1">css3 新增特性有哪些 <a class="header-anchor" href="#css3-新增特性有哪些" aria-label="Permalink to &quot;css3 新增特性有哪些&quot;">​</a></h3><p>答：css3 比 css2 多了好多针对移动端的特性，比如：圆角：border-radius,盒阴影：box-shadow,还有动画：transition(过渡),transform（实现位移，倾斜，旋转，绽放）,animation（关键帧动画）等</p><h3 id="如何实现一个-div-垂直居中-至少-3-种方法" tabindex="-1">如何实现一个 div 垂直居中（至少 3 种方法） <a class="header-anchor" href="#如何实现一个-div-垂直居中-至少-3-种方法" aria-label="Permalink to &quot;如何实现一个 div 垂直居中（至少 3 种方法）&quot;">​</a></h3><p>答：其实实现水平垂直剧中方法有很多：</p><p>第一种：定位：第一种思路：通过给 div 设置绝对定位，并且 left,right,top,bottom 设置为 0,margin:auto 即可以水平垂直居中</p><p>第二种思路：通过给 div 设置绝对定位，left 为 50%,top 为 50%,再给 div 设置距左是自身的一半即：margin-left:自身宽度/2,margin-top:自身高度/2。</p><p>第三种思路：通过给 div 设置绝对定位，left 为 50%,top 为 50%，再给 div 设置跨左和跟上是自身的一半：transform:translate3d(-50%,-50%,0)</p><p>第四种：flex 布局:思路：有两个 div，父级 div 和子级 div，给父级 div 设置 display:flex,并且设置父级 div 的水平居中 justify-content:center，并且给父级 div 设置垂直居中 align-items:center 即可</p><h3 id="clearfix-是解决什么问题的-另一种问法-div-塌陷问题如何解决的-或者说一下-bfc" tabindex="-1">clearfix 是解决什么问题的（另一种问法 div 塌陷问题如何解决的,或者说一下 BFC） <a class="header-anchor" href="#clearfix-是解决什么问题的-另一种问法-div-塌陷问题如何解决的-或者说一下-bfc" aria-label="Permalink to &quot;clearfix 是解决什么问题的（另一种问法 div 塌陷问题如何解决的,或者说一下 BFC）&quot;">​</a></h3><p>答：解决的方法有很多，主要目的是让父级元素有高度</p><p>方法一：给父级元素设置绝对定位：position:absolute</p><p>方法二：给父级元素设置 overflow:hidden;</p><p>方法三：通过伪对象来实现</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.clearfix</span><span style="color:#56B6C2;">:after</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">	content: </span><span style="color:#98C379;">&quot; &quot;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">	display: </span><span style="color:#D19A66;">block</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">	clear: </span><span style="color:#D19A66;">both</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">	height: </span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="说一下你对盒模型的理解-包括-ie-和-w3c-标准盒模型" tabindex="-1">说一下你对盒模型的理解(包括 IE 和 w3c 标准盒模型) <a class="header-anchor" href="#说一下你对盒模型的理解-包括-ie-和-w3c-标准盒模型" aria-label="Permalink to &quot;说一下你对盒模型的理解(包括 IE 和 w3c 标准盒模型)&quot;">​</a></h3><p>答：哦，盒模型其实就是浏览器把一个个标签都看一个形象中的盒子，那每个盒子（即标签）都会有内容(width,height)，边框(border)，以及内容和边框中间的缝隙（即内间距 padding），还有盒子与盒子之间的外间距（即 margin）,用图表示为：</p><p><img src="`+m+'" alt="img"></p><p>当然盒模型包括两种：IE 盒模型和 w3c 标准盒模型</p><p>IE 盒模型总宽度即就是 width 宽度=border+padding+内容宽度</p><p>标准盒模型总宽度＝ border+padding+width</p><p>那如何在 IE 盒模型宽度和标准盒模型总宽度之间切换呢，可以通过 box-sizing:border-box 或设置成 content-box 来切换</p><p>其中：box-sizing：border-box //IE 盒模型</p><p>box-sizing：content-box //w3c 盒模型</p><h3 id="css3-动画" tabindex="-1">css3 动画 <a class="header-anchor" href="#css3-动画" aria-label="Permalink to &quot;css3 动画&quot;">​</a></h3><p>答：哦，您问的 css3 动画啊，css3 动画大致上包括两种：</p><p>第一种：过渡动画：主要通过 transition 来实现，通过设置过渡属性，运动时间，延迟时间和运动速度实现。</p><p>第二种：关键帧动画：主要通过 animation 配合@keyframes 实现</p><p>transition 动画和 animation 动画的主要区别有两点：</p><p>第一点 transition 动画需要事件来触发，animation 不需要</p><p>第二点:transition 只要开始结束两种状态，而 animation 可以实现多种状态，并且 animation 是可以做循环次数甚至是无限运动</p><h3 id="rem-和-em-的区别" tabindex="-1">rem 和 em 的区别 <a class="header-anchor" href="#rem-和-em-的区别" aria-label="Permalink to &quot;rem 和 em 的区别&quot;">​</a></h3><p>答：rem 和 em 都是相对单位，主要参考的标签不同：rem 是相对于根字号，即相对于<code>&lt;html&gt;</code>标签的 font-size 实现的，浏览器默认字号是 font-size:16pxem:是相对于父元素标签的字号，和百分比%类似，%也是相对于父级的，只不过是%相对于父级宽度的，而 em 相对于父级字号的</p><h3 id="手机端如何做适配的" tabindex="-1">手机端如何做适配的 <a class="header-anchor" href="#手机端如何做适配的" aria-label="Permalink to &quot;手机端如何做适配的&quot;">​</a></h3><p>答：前端做适配没有最好的方法，只有适合的方法，目前前端主要做适配的方法有：百分比，em,rem,媒体查询(即 media query),flex 布局（即弹性盒），vw,vh 等目前我在项目中用的多的是 rem，flex 布局，有时会用到媒体查询，在做 pc 响应式布局时用主要是用了一个手淘的 js 库<a href="https://link.zhihu.com/?target=http%3A//caibaojian.com/t/flexible-js" target="_blank" rel="noreferrer">flexible.js</a>,在页面变化时,检测页面宽度,除以 10 份,动态的赋值给 font-size.属性.;</p><p>而页面的布局我是通过 rem 来进行布局的,所以就可以适配所有的移动端设备了</p><h3 id="vw-和-vh-了解吗" tabindex="-1">vw 和 vh 了解吗 <a class="header-anchor" href="#vw-和-vh-了解吗" aria-label="Permalink to &quot;vw 和 vh 了解吗&quot;">​</a></h3><p>答：vw 和 vh 是最近 2 年才慢慢火起来的 css 布局单位，现在已经被一些公司在使用，</p><p>vw 和 vh 分别相对于屏幕宽度和屏幕高度的，1vw 相当于屏幕宽度的 1%,100vw 相当于满屏宽度 100%,</p><p>vh 和 vh 类似，只不过是相对于屏幕高度的，1vh 相当于屏幕高度的 1%,100vh 相当于满屏高度的 100%,</p><h3 id="你平时怎么写-css-或者说用过-css-预处理器吗-用过-less-和-sass-吗" tabindex="-1">你平时怎么写 css（或者说用过 css 预处理器吗，用过 Less 和 SASS 吗？） <a class="header-anchor" href="#你平时怎么写-css-或者说用过-css-预处理器吗-用过-less-和-sass-吗" aria-label="Permalink to &quot;你平时怎么写 css（或者说用过 css 预处理器吗，用过 Less 和 SASS 吗？）&quot;">​</a></h3><p>答：一般咱们说我平时写 css 用 less，可以定义变量，嵌套，混入等功能，sass 语法和 less 类似都是 css 预处理器，方便开发人员写快速高效写 css</p><h3 id="h5-相关" tabindex="-1">H5 相关 <a class="header-anchor" href="#h5-相关" aria-label="Permalink to &quot;H5 相关&quot;">​</a></h3><h3 id="cookie-localstorage-和-sessionstorage-的区别" tabindex="-1">cookie,localStorage 和 sessionStorage 的区别 <a class="header-anchor" href="#cookie-localstorage-和-sessionstorage-的区别" aria-label="Permalink to &quot;cookie,localStorage 和 sessionStorage 的区别&quot;">​</a></h3><p>答：cookie 可以设置失效时间，但没有自己的存取取的方法，需要时封装，每次请求时跟随请求发送,而 localStorage 和 sessionStorage 可以有自己存取的方法例如：setItem(),getItem(),removeItem(),clear() 如：localStorage.setItem(‘属性’，值)</p><p><img src="'+v+'" alt="img"></p><h3 id="autio-video" tabindex="-1">autio,video <a class="header-anchor" href="#autio-video" aria-label="Permalink to &quot;autio,video&quot;">​</a></h3><p>答：H5 提供的音频和视频组件，可以实现视频播放，我以前用它做过音乐播放器，不过好久没用了，里面有 play,pause 还有获取当前时间和总时间的方法，得看一下 audio,video 的 API，用时我也能很快上手的基它</p><h3 id="兼容性相关" tabindex="-1">兼容性相关 <a class="header-anchor" href="#兼容性相关" aria-label="Permalink to &quot;兼容性相关&quot;">​</a></h3><p>pc 端：一般是 IE 兼容的问题，例如：利用 css hack 来解决 * ，_,等 JS 有特性匹配来解决某个 JS 方法是否存在</p><p>手机端：主要遇到过移动端 300ms 延迟和点透问题，可以通过 fastclick 插件解决性能优化相关：</p><p>答：性能优化是一个很大的一个话题：优化的方面有很多，1 是网络加载方面的优化：例如：减少 http 请求（合并文件，css 雪碧图，图片懒加载），减少 dom 操作（dom 缓存），代码封装，第三方库用 cdn 加载，gzip 压缩等 IE8 如何支持语义化标签一个库 html5shiv.js,直接引入就 ok,大家可以百度下这个的文件,原理就是把语义化标签在低版本浏览器转化成了块级元素,让浏览器可以解析谷歌浏览器如何显示 12px 以下的字号中文版的 chrome 有个 12px 字体限制的问题，就是当字体小于 12px 时候都以 12px 来显示，这个问题在中文网站中并不突出，因为中文字体为了显示清晰一般都定义为大于或等于 12px，但如果是一些英文网站那就不好说了，这时 12px 的限制就会破坏页面的美感，甚至因为文字变大而导致页面变形。以前有个属性#chrome10px{ -webkit-text-size-adjust:none; font-size:10px; },但是新版谷歌已经不起作用了.我们可以通过 css3 的缩放来实现这个问题,比方说我要展示 10px 的文字,我可以通过设置字体 20px,然后 scale(0.5);</p><h3 id="常用算法相关" tabindex="-1">常用算法相关 <a class="header-anchor" href="#常用算法相关" aria-label="Permalink to &quot;常用算法相关&quot;">​</a></h3><p>排序，去重，地址栏解析成对象，深拷贝和浅拷贝。。。</p><p>一、数组排序：</p><p><img src="'+g+'" alt="img">二、</p><p>数组去重：答：第一种：利用 ES6 的 set 来实现 例如：[...<strong>new</strong> Set(arr)]第二种：借用临时对象的方式</p><p><img src="'+A+'" alt="img"></p><p>三、地址栏解析成对象：答：</p><p><img src="'+F+'" alt="img"></p><p>四、对象深拷贝，浅拷贝的解理：答：对象浅拷贝可以理解为改变一个对象属性值，另一个对象属性也会发生改变，即互相影响，对象深拷贝即就是说改变一个对象属性，另一个对象属性值不会发生改变，可以通过多种方法来实现对象深拷贝，第一种方法：通过 JSON.stringify 和 JSON.parse 来实现 var obj={name:’全栈 1902A’}var obj2=JSON.parse(JSON.stringify(obj))第二种方法：通过递归来实现</p><p><img src="'+f+`" alt="img"></p><p>同学们可以参照以下代码,看下函数兼容性处理,以及封装</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#56B6C2;">*</span><span style="color:#C678DD;">var</span><span style="color:#ABB2BF;">* </span><span style="color:#E06C75;">EventUtil</span><span style="color:#56B6C2;">=</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">[</span><span style="color:#E06C75;">addHandler</span><span style="color:#ABB2BF;">](</span><span style="color:#E06C75;font-style:italic;">https</span><span style="color:#ABB2BF;">:</span><span style="color:#7F848E;font-style:italic;">//link.zhihu.com/?target=https%3A//www.cnblogs.com/hykun/p/EventUtil.html%23addHandler):*function*(*element*,*type*,*handler*){ //添加事件if(element.addEventListener){element.addEventListener(type,handler,false); //使用DOM2级方法添加事件}else if(element.attachEvent){ //使用IE方法添加事件element.attachEvent(&quot;on&quot;+type,handler);}else{element[&quot;on&quot;+type]=handler; //使用DOM0级方法添加事件}},[removeHandler](https://link.zhihu.com/?target=https%3A//www.cnblogs.com/hykun/p/EventUtil.html%23removeHandler):*function*(*element*,*type*,*handler*){ //取消事件if(element.removeEventListener){element.removeEventListener(type,handler,false);}else if(element.detachEvent){element.detachEvent(&quot;on&quot;+type,handler);}else{element[&quot;on&quot;+type]=null;}},[getEvent](https://link.zhihu.com/?target=https%3A//www.cnblogs.com/hykun/p/EventUtil.html%23getEvent):*function*(*event*){ //使用这个方法跨浏览器取得event对象return *event*?*event*:*window*.*event*;},</span></span>
<span class="line"><span style="color:#ABB2BF;">[</span><span style="color:#E5C07B;">getTarget</span><span style="color:#ABB2BF;">](</span><span style="color:#E06C75;font-style:italic;">https</span><span style="color:#ABB2BF;">:</span><span style="color:#7F848E;font-style:italic;">//link.zhihu.com/?target=https%3A//www.cnblogs.com/hykun/p/EventUtil.html%23getTarget):*function*(*event*){ //返回事件的实际目标return *event*.target||*event*.srcElement;},</span></span>
<span class="line"><span style="color:#ABB2BF;">[</span><span style="color:#E5C07B;">preventDefault</span><span style="color:#ABB2BF;">](</span><span style="color:#E06C75;font-style:italic;">https</span><span style="color:#ABB2BF;">:</span><span style="color:#7F848E;font-style:italic;">//link.zhihu.com/?target=https%3A//www.cnblogs.com/hykun/p/EventUtil.html%23preventDefault):*function*(*event*){ //阻止事件的默认行为if(*event*.preventDefault){*event*.preventDefault();}else{*event*.returnValue=false;}},[stopPropagation](https://link.zhihu.com/?target=https%3A//www.cnblogs.com/hykun/p/EventUtil.html%23stopPropagation):*function*(*event*){ //立即停止事件在DOM中的传播//避免触发注册在document.body上面的事件处理程序if(*event*.stopPropagation){*event*.stopPropagation();}else{*event*.cancelBubble=true;}}}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="自我成长相关" tabindex="-1">自我成长相关 <a class="header-anchor" href="#自我成长相关" aria-label="Permalink to &quot;自我成长相关&quot;">​</a></h3><h4 id="平时怎么学习新技术的" tabindex="-1">平时怎么学习新技术的？ <a class="header-anchor" href="#平时怎么学习新技术的" aria-label="Permalink to &quot;平时怎么学习新技术的？&quot;">​</a></h4><p>答：</p><p>上官网看文档，上 github 上找相关开源项目练手，</p><p>上技术社区博客园，csdn,51cto,掘金，简书参加技术问题讨论，上知乎，</p><p>通过专业书籍（《JavaScript 高级程序设计》--红宝石书，《JavaScript 权威指南》--犀牛书）</p><p>系统学习，加入相关技术群参考讨论，</p><h4 id="未来的职业规划是什么" tabindex="-1">未来的职业规划是什么？ <a class="header-anchor" href="#未来的职业规划是什么" aria-label="Permalink to &quot;未来的职业规划是什么？&quot;">​</a></h4><p>答：2 年内先做好技术，小有所成后，其他机会也就慢慢来了 Websocket 知识点：它是一种做及时性聊天的技术,在用的过程中,首先初始化一个 websocket 实例,当我要发送数据的时候触发 onopen 方法里面的 send 方法，携带发送的内容，接收服务器的数据是 onmessage 方法，关闭本次长链接用 onclose 方法这个东西其实和 ajax 比较像，有具体固定的格式步骤。</p><p>只不是这种是长链接，ajax 技术是短连接，局部刷新</p>`,242),x=[C];function q(k,w,D,S,j,_){return n(),a("div",null,x)}const O=s(E,[["render",q]]);export{J as __pageData,O as default};
